       xmlns: "http://docs.oasis-open.org/ns/xri/xrd-1.0",
       "xmlns:hm": "http://host-meta.net/ns/1.0"
     }, "hm:Host": host,
     Link: %{
       rel: "lrdd",
       type: "application/jrd+json",
       template: "#{base_url}/.well-known/webfinger?resource={uri}"
     }}
  )
end

def get_scopes do
  @global_scope |> Map.values() |> Enum.concat() |> Enum.concat([:read, :write])
end

def get_category_statistics(_parent, _params, _context) do
  {:ok, StatisticsModule.category_statistics()}
end

def lowercase_domain(email) when is_binary(email) do
  case split_email(email) do
    [user_part, domain_part] -> {:ok, "#{user_part}@#{String.downcase(domain_part)}"}
    _ -> {:error, :invalid_email}
  end
end
def lowercase_domain(_) do
  {:error, :invalid_email}
end

def cachex_spec(name, limit, default, interval, fallback \\ nil) do
  %{
    id: String.to_atom("cache_#{to_string(name)}"),
    start:
      {Cachex, :start_link,
       [
         name,
         Keyword.merge(
           cachex_options(limit, default, interval),
           fallback_options(fallback)
         )
       ]}
  }
end

